// Constrói o pedido Gemini para redigir o email de follow-up.
// Prompt documentado em prompts/followup-email.md
const CALCOM_LINK = 'https://cal.com/andre-correia-1ntsbg/consulta-de-avaliacao-30-min';

const lead = $input.first().json;

const system = `És o assistente de comunicação da Clínica Vitalis, uma clínica de saúde portuguesa.
Escreves emails de resposta a pessoas que preencheram o formulário de contacto.
Devolves APENAS um objeto JSON válido com as chaves "assunto" e "corpo".

Regras de escrita:
- Português europeu, tratamento por "si" (nunca "você" explícito, nunca tuteares).
- Máximo 120 palavras no corpo. Sem parágrafos longos.
- Adapta o tom ao campo "tom_sugerido" recebido.
- Estrutura em 3 parágrafos curtos, SEPARADOS por uma linha em branco (usa \\n\\n
  no valor JSON de "corpo" entre cada parágrafo — nunca escrevas tudo num único
  bloco de texto):
  1. Cumprimento com o primeiro nome + mostrar que a mensagem foi lida (referir
     o motivo do contacto por palavras próprias).
  2. Convite para marcar uma consulta de avaliação, com o link de marcação.
  3. Despedida em nome da "Equipa da Clínica Vitalis".
- Se urgencia = "alta": referir no 2º parágrafo que há vagas nos próximos dias e
  que a equipa dá prioridade ao caso. Nunca prometas resultados clínicos.

Restrições (obrigatórias):
- NUNCA incluas diagnósticos, conselhos médicos ou promessas de tratamento/cura.
- NUNCA inventes preços, horários, moradas ou nomes de profissionais.
- O único link permitido é o link de marcação fornecido.`;

const user = `Dados do lead:
Nome: ${lead.nome}
Serviço: ${lead.servico}
Urgência: ${lead.urgencia}
Resumo do pedido: ${lead.resumo}
Tom sugerido: ${lead.tom_sugerido}
Link de marcação: ${CALCOM_LINK}`;

return [{
  json: {
    body: {
      system_instruction: { parts: [{ text: system }] },
      contents: [{ role: 'user', parts: [{ text: user }] }],
      generationConfig: { responseMimeType: 'application/json', temperature: 0.7 }
    }
  }
}];

// Parse defensivo do email redigido pelo Gemini.
const lead = $('Recebe dados do WF1').first().json;
const resp = $input.first().json;

let text = resp.candidates?.[0]?.content?.parts?.[0]?.text ?? '';
text = text.trim().replace(/^```(?:json)?/i, '').replace(/```$/, '').trim();

let email;
try {
  email = JSON.parse(text);
} catch (e) {
  throw new Error('Resposta do Gemini não é JSON válido: ' + text);
}

if (!email.assunto || !email.corpo) {
  throw new Error('Resposta sem assunto/corpo: ' + text);
}

return [{
  json: {
    destinatario: lead.email,
    nome: lead.nome,
    assunto: email.assunto,
    corpo: email.corpo
  }
}];

// Prepara a linha de log (só corre se o envio Gmail teve sucesso).
const email = $('Interpretar email').first().json;
return [{
  json: {
    timestamp: new Date().toLocaleString('pt-PT', { timeZone: 'Europe/Lisbon', day: '2-digit', month: '2-digit', year: 'numeric', hour: '2-digit', minute: '2-digit' }).replace(',', ''),
    tipo: 'followup',
    destinatario: email.destinatario,
    assunto: email.assunto
  }
}];
